<template lang="html">
  <div id="main">
    <nav class="navbar is-fixed-top" role="navigation" aria-label="main navigation">
  <div class="navbar-brand">
    <a class="navbar-item" href="/">
      <p class="title">Zhaolin Lau</p>
    </a>

    <a role="button" class="navbar-burger" aria-label="menu" aria-expanded="false" data-target="navbar">
      <span aria-hidden="true"></span>
      <span aria-hidden="true"></span>
      <span aria-hidden="true"></span>
    </a>
  </div>

  <div id="navbar" class="navbar-menu has-text-centered animate__animated">
    <div class="navbar-end">
      <a class="navbar-item mx-6" href="#main">
        <span class="icon-text">
          <span class="icon">
            <span class="mdi mdi-home-outline mdi-36px"></span>
          </span>
          <span class="subtitle">Home</span>
        </span>
      </a>

      <a class="navbar-item mx-6" href="#about">
        <span class="icon-text">
          <span class="icon">
            <span class="mdi mdi-file-account-outline mdi-36px"></span>
          </span>
          <span class="subtitle">About</span>
        </span>
      </a>

      <a class="navbar-item mx-6" href="#works">
        <span class="icon-text">
          <span class="icon">
            <span class="mdi mdi-artstation mdi-36px"></span>
          </span>
          <span class="subtitle">Works</span>
        </span>
      </a>

      <a class="navbar-item mx-6" href="#contact">
        <span class="icon-text">
          <span class="icon">
            <span class="mdi mdi-phone-outline mdi-36px"></span>
          </span>
          <span class="subtitle">Contact</span>
        </span>
      </a>
    </div>
  </div>
</nav>
<section class="hero is-primary is-fullheight is-bold">
  <div class="hero-body">
    <div class="container content is-large has-text-centered">
        <div class="animate__animated animate__bounceIn animate__fast"><img class="animate__animated animate__rubberBand animate__delay-1s" src="../assets/welcome.svg" alt="Welcome"></div>
        <div class="mt-6"><a href="#about" class="scroll animate__animated animate__fadeInDown animate__faster animate__delay-2s"><img class="mt-6 animate__animated animate__shakeY animate__delay-2s animate__repeat-2" src="../assets/chevron-double-down.png" alt="Scroll Down"></a></div>
    </div>
  </div>
</section>
  </div>
</template>

<script>
export default {
  mounted() {
    document.addEventListener('DOMContentLoaded', () => {

      // Get all "navbar-burger" elements
      const $navbarBurgers = Array.prototype.slice.call(document.querySelectorAll('.navbar-burger'), 0);

      // Check if there are any navbar burgers
      if ($navbarBurgers.length > 0) {

        // Add a click event on each of them
        $navbarBurgers.forEach(el => {
          el.addEventListener('click', () => {

            // Get the target from the "data-target" attribute
            const target = el.dataset.target;
            const $target = document.getElementById(target);

            // Toggle the "is-active" class on both the "navbar-burger" and the "navbar-menu"
            el.classList.toggle('is-active');
            $target.classList.toggle('is-active');
          });
        });
      }
    });
  }
}
</script>
